# weather_server.py
import httpx
import mcp.server.stdio
from mcp.server import Server
from mcp.types import Tool, TextContent

app = Server("weather-server")

@app.list_tools()
async def list_tools() -> list[Tool]:
    return [
        Tool(
            name="get_weather",
            description=(
                "Return the current weather for a city. "
                "Use when the user asks about temperature, weather conditions, or forecasts."
            ),
            inputSchema={
                "type": "object",
                "properties": {
                    "city": {
                        "type": "string",
                        "description": "City name, e.g. 'Paris' or 'Tokyo'.",
                    },
                    "units": {
                        "type": "string",
                        "enum": ["metric", "imperial"],
                        "description": "Temperature units. Default: metric.",
                        "default": "metric",
                    },
                },
                "required": ["city"],
                "additionalProperties": False,
            },
        )
    ]

@app.call_tool()
async def call_tool(name: str, arguments: dict) -> list[TextContent]:
    if name == "get_weather":
        city = arguments["city"]
        units = arguments.get("units", "metric")
        # In production, call a real weather API:
        async with httpx.AsyncClient() as client:
            resp = await client.get(
                "https://wttr.in/{city}?format=j1".format(city=city),
                timeout=5,
            )
            data = resp.json()
            temp = data["current_condition"][0]["temp_C" if units == "metric" else "temp_F"]
            desc = data["current_condition"][0]["weatherDesc"][0]["value"]
        return [TextContent(
            type="text",
            text=f"Weather in {city}: {desc}, {temp}°{'C' if units == 'metric' else 'F'}",
        )]
    return [TextContent(type="text", text=f"Unknown tool: {name}")]

if __name__ == "__main__":
    import asyncio
    asyncio.run(mcp.server.stdio.run(app))

